<?php

declare(strict_types=1);

use HalalPulse\Multibagger\MultibaggerScoringEngine;
use HalalPulse\Multibagger\ResearchEvidenceUrl;
use HalalPulse\Sharia\DecimalMath;
use HalalPulse\Web\Page;
use HalalPulse\Web\Request;
use HalalPulse\Web\Response;
use HalalPulse\Web\WebApplication;

$config=require dirname(__DIR__).'/app/bootstrap.php';$app=WebApplication::boot($config);$user=$app->session->currentUser($app->users);if($user===null)Response::redirect('/login.php',302);
$companyId=Request::isPost()?(int)Request::postString('company_id'):Request::queryInt('id',0);$company=$companyId>0?$app->multibagger->company($companyId):null;if($company===null){http_response_code(404);exit('Company not found.');}
$validDate=static function(string $value):bool{$date=DateTimeImmutable::createFromFormat('!Y-m-d',$value);return$date!==false&&$date->format('Y-m-d')===$value;};
$redirectPath=static fn(int$id,string$period):string=>'/multibagger-company.php?id='.$id.($period===''?'':'&period='.rawurlencode($period));
$postList=static function(string$key):array{$values=$_POST[$key]??[];if(!is_array($values))return[];return array_values(array_filter($values,'is_string'));};

if(Request::isPost()){
    if(!$app->session->verifyCsrf(Request::postString('csrf_token',false))){http_response_code(400);exit('Invalid request token.');}
    $action=Request::postString('action');$period=Request::postString('period_end');
    try{
        if(!$validDate($period))throw new InvalidArgumentException('Choose a valid reporting period end date.');
        $methodology=$app->multibagger->activeMethodology();if($methodology===null)throw new InvalidArgumentException('Activate the reviewed multibagger methodology first.');
        if($action==='save_factor'){
            $factorKey=Request::postString('factor_key');$grade=(int)Request::postString('grade');$note=Request::postString('evidence_note');$sourceUrl=Request::postString('evidence_source_url');$documentText=Request::postString('source_document_id');$documentId=$documentText===''?null:(int)$documentText;$governmentText=Request::postString('government_tailwind_review_id');$governmentReviewId=$governmentText===''?null:(int)$governmentText;
            if(!in_array($factorKey,$methodology->factorKeys(),true)||$grade<1||$grade>10)throw new InvalidArgumentException('Choose a valid factor and grade from 1 to 10.');
            if(mb_strlen($note)<3||mb_strlen($note)>1000)throw new InvalidArgumentException('Evidence note must contain 3 to 1,000 characters.');
            if($documentId!==null&&($documentId<1||!$app->multibagger->documentBelongsToCompany($documentId,$companyId)))throw new InvalidArgumentException('The selected PDF does not belong to this company.');
            if($factorKey==='macro_tailwind'){$governmentEvidence=$governmentReviewId===null?null:$app->government->approvedTailwind($governmentReviewId);if($governmentEvidence===null)throw new InvalidArgumentException('Choose a current, human-approved government tailwind review for the macro factor.');$sourceUrl=(string)$governmentEvidence['official_url'];$documentId=null;}
            if($factorKey!=='macro_tailwind'&&$sourceUrl===''&&$documentId===null)throw new InvalidArgumentException('Link an official source URL or a stored filing PDF.');
            if($factorKey!=='macro_tailwind'&&$sourceUrl!==''&&!ResearchEvidenceUrl::isAllowed($sourceUrl))throw new InvalidArgumentException('Evidence URL must use an allowed official exchange, regulator, or government HTTPS host.');
            if($factorKey!=='macro_tailwind')$governmentReviewId=null;
            $app->multibagger->saveFactorReview($companyId,$period,$factorKey,$grade,$note,$sourceUrl===''?null:$sourceUrl,$documentId,$governmentReviewId,$user->id);$app->logger->info('Multibagger factor reviewed.',['company_id'=>$companyId,'period_end'=>$period,'factor_key'=>$factorKey,'grade'=>$grade,'government_review_id'=>$governmentReviewId,'user_id'=>$user->id]);$app->session->flash('success','Factor review saved as a new audit record.');
        }elseif($action==='save_valuation'){
            $decimalFields=['eps','book_value_per_share','dcf_value_per_share','current_price'];$values=[];foreach($decimalFields as$field){$value=Request::postString($field);if(preg_match('/^(?:0|[1-9]\d{0,17})(?:\.\d{1,6})?$/D',$value)!==1||$value==='0')throw new InvalidArgumentException('Every valuation number must be a positive decimal.');$values[$field]=$value;}
            $currency=strtoupper(Request::postString('currency'));$assumptions=Request::postString('dcf_assumptions_note');$note=Request::postString('valuation_evidence_note');$sourceUrl=Request::postString('valuation_evidence_source_url');$documentText=Request::postString('valuation_document_id');$documentId=$documentText===''?null:(int)$documentText;
            if(preg_match('/^[A-Z]{3}$/D',$currency)!==1||mb_strlen($assumptions)<10||mb_strlen($assumptions)>1000||mb_strlen($note)<3||mb_strlen($note)>1000)throw new InvalidArgumentException('Currency, DCF assumptions, or valuation evidence is incomplete.');
            if(!ResearchEvidenceUrl::isAllowed($sourceUrl))throw new InvalidArgumentException('Valuation evidence URL must use an allowed official HTTPS host.');
            if($documentId!==null&&!$app->multibagger->documentBelongsToCompany($documentId,$companyId))throw new InvalidArgumentException('The selected valuation PDF does not belong to this company.');
            $values+=['currency'=>$currency,'dcf_assumptions_note'=>$assumptions,'evidence_note'=>$note,'evidence_source_url'=>$sourceUrl,'source_document_id'=>$documentId];$app->multibagger->saveValuationReview($companyId,$period,$values,$user->id);$app->logger->info('Multibagger valuation reviewed.',['company_id'=>$companyId,'period_end'=>$period,'user_id'=>$user->id]);$app->session->flash('success','Graham/DCF valuation evidence saved.');
        }elseif($action==='save_risk'){
            $marketCap=Request::postString('market_cap_crore');$note=Request::postString('risk_evidence_note');$sourceUrl=Request::postString('risk_evidence_source_url');if(preg_match('/^(?:0|[1-9]\d{0,17})(?:\.\d{1,6})?$/D',$marketCap)!==1||$marketCap==='0')throw new InvalidArgumentException('Market capitalization must be a positive crore value.');if(mb_strlen($note)<3||mb_strlen($note)>1000||!ResearchEvidenceUrl::isAllowed($sourceUrl))throw new InvalidArgumentException('Risk evidence note or official source URL is invalid.');
            $riskConfig=$methodology->definition['microcap_adjustments'];$allowedRed=array_column($riskConfig['red_flags'],'key');$allowedGreen=array_column($riskConfig['green_flags'],'key');$red=array_values(array_intersect($postList('red_flags'),$allowedRed));$green=array_values(array_intersect($postList('green_flags'),$allowedGreen));$app->multibagger->saveRiskReview($companyId,$period,$marketCap,$red,$green,$note,$sourceUrl,$user->id);$app->logger->info('Multibagger risk review saved.',['company_id'=>$companyId,'period_end'=>$period,'red_flag_count'=>count($red),'green_flag_count'=>count($green),'user_id'=>$user->id]);$app->session->flash('success','Market-cap and microcap risk review saved.');
        }elseif($action==='run_score'){
            $shariaPass=$app->multibagger->currentShariaPass($companyId,$period);if($shariaPass===null)throw new InvalidArgumentException('A same-period pass under the active Sharia policy is required before scoring.');$result=(new MultibaggerScoringEngine(new DecimalMath()))->score($methodology,$shariaPass,$app->multibagger->factorReviews($companyId,$period),$app->multibagger->valuationReview($companyId,$period),$app->multibagger->riskReview($companyId,$period));$scoreId=$app->multibagger->recordScore($companyId,$methodology,(int)$shariaPass['id'],$period,$result,$user->id);$app->logger->info('Multibagger score recorded.',['score_id'=>$scoreId,'company_id'=>$companyId,'status'=>$result->status,'final_score'=>$result->finalScore,'alert_eligible'=>$result->alertEligible,'user_id'=>$user->id]);$app->session->flash($result->status==='scored'?'success':'warning',$result->status==='scored'?'Score '.$result->finalScore.' / 10 recorded.':'Evidence remains insufficient; no score was assigned.');
        }else throw new InvalidArgumentException('Invalid multibagger review action.');
    }catch(InvalidArgumentException$exception){$app->session->flash('error',$exception->getMessage());}catch(Throwable$exception){$app->logger->error('Multibagger action failed.',['company_id'=>$companyId,'action'=>$action,'exception_class'=>$exception::class,'user_id'=>$user->id]);$app->session->flash('error','The action could not be completed. Run the health check and inspect the private application log.');}
    $app->session->rotateCsrfToken();Response::redirect($redirectPath($companyId,$period));
}

$methodology=$app->multibagger->activeMethodology();$selectedPeriod=Request::queryString('period');if(!$validDate($selectedPeriod))$selectedPeriod=(new DateTimeImmutable('now'))->format('Y-m-d');$shariaPass=$app->multibagger->currentShariaPass($companyId,$selectedPeriod);$factors=$app->multibagger->factorReviews($companyId,$selectedPeriod);$valuation=$app->multibagger->valuationReview($companyId,$selectedPeriod);$risk=$app->multibagger->riskReview($companyId,$selectedPeriod);$documents=$app->multibagger->documentsForCompany($companyId);$governmentTailwinds=$app->government->approvedTailwinds();$history=$app->multibagger->scoreHistory($companyId);
Page::begin((string)$company['symbol'].' potential review',(string)$config->get('app.name','HalalPulse'),$user,'multibagger',$app->session->csrfToken());
?>
