fficial price/evidence URL</label><input id="valuation_evidence_source_url" name="valuation_evidence_source_url" type="url" value="<?=Page::escape($valuation['evidence_source_url']??'')?>" required><label for="valuation_document_id">Financial statement PDF (optional)</label><select id="valuation_document_id" name="valuation_document_id"><option value="">No linked PDF</option><?php foreach($documents as$document):?><option value="<?=Page::escape($document['id'])?>" <?=((int)($valuation['source_document_id']??0)===(int)$document['id'])?'selected':''?>>#<?=Page::escape($document['id'])?> · <?=Page::escape($document['subject'])?></option><?php endforeach;?></select><button class="button button-primary">Save valuation review</button></form></article>
