n=json_decode((string)($risk['green_flags']??'[]'),true);$selectedGreen=is_array($selectedGreen)?$selectedGreen:[];foreach($methodology->definition['microcap_adjustments']['green_flags'] as$flag):?><label class="check-row"><input type="checkbox" name="green_flags[]" value="<?=Page::escape($flag['key'])?>" <?=in_array($flag['key'],$selectedGreen,true)?'checked':''?>> <span><?=Page::escape($flag['label'])?></span></label><?php endforeach;?></fieldset></div><label for="risk_evidence_note">Risk review evidence</label><textarea id="risk_evidence_note" name="risk_evidence_note" maxlength="1000" required><?=Page::escape($risk['evidence_note']??'')?></textarea><button class="button button-primary">Save risk review</button></form></section>
